import javax.jws.WebService;
import javax.jws.WebMethod;
import javax.xml.ws.BindingType;
import javax.xml.ws.soap.SOAPBinding;
import javax.xml.ws.soap.MTOM;
import javax.xml.ws.handler.MessageContext;
import javax.xml.soap.SOAPMessage;
import javax.xml.soap.SOAPHeader;
import javax.xml.soap.SOAPElement;
import javax.xml.namespace.QName;
import java.util.Date;
import java.util.Map;
import java.util.GregorianCalendar;
import java.text.SimpleDateFormat;
import java.util.TimeZone;

@WebService
@BindingType(SOAPBinding.SOAP11HTTP_MTOM)
@MTOM
public class PaymentGatewayService {
    
    private static final long TIMESTAMP_TOLERANCE = 300000; // 5 minutes
    
    @WebMethod
    public PaymentResponse processPayment(PaymentRequest request) {
        try {
            // Validate timestamp
            validateTimestamp();
            
            // Validate payment request
            if (request == null || request.getAmount() <= 0) {
                return createErrorResponse("Invalid payment request");
            }
            
            // Process payment logic here
            PaymentResponse response = new PaymentResponse();
            response.setTransactionId(generateTransactionId());
            response.setStatus("SUCCESS");
            response.setAmount(request.getAmount());
            response.setCurrency(request.getCurrency());
            
            return response;
            
        } catch (Exception e) {
            return createErrorResponse(e.getMessage());
        }
    }
    
    private void validateTimestamp() throws Exception {
        MessageContext context = MessageContext.getCurrentContext();
        Map<String, Object> headers = (Map<String, Object>) context.get(MessageContext.HTTP_REQUEST_HEADERS);
        
        SOAPMessage soapMessage = context.getMessage();
        SOAPHeader header = soapMessage.getSOAPHeader();
        
        if (header == null) {
            throw new Exception("Missing SOAP header");
        }
        
        // Extract timestamp from WS-Security header
        SOAPElement timestampElement = (SOAPElement) header.getElementsByTagNameNS(
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", 
            "Timestamp"
        ).item(0);
        
        if (timestampElement == null) {
            throw new Exception("Missing timestamp in WS-Security header");
        }
        
        String created = timestampElement.getElementsByTagNameNS(
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", 
            "Created"
        ).item(0).getTextContent();
        
        String expires = timestampElement.getElementsByTagNameNS(
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd", 
            "Expires"
        ).item(0).getTextContent();
        
        // Parse timestamps
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
        sdf.setTimeZone(TimeZone.getTimeZone("UTC"));
        
        Date createdDate = sdf.parse(created);
        Date expiresDate = sdf.parse(expires);
        Date now = new Date();
        
        // Check for replay attacks
        if (now.getTime() - createdDate.getTime() > TIMESTAMP_TOLERANCE) {
            throw new Exception("Timestamp expired or replay attack detected");
        }
        
        if (now.getTime() > expiresDate.getTime()) {
            throw new Exception("Timestamp expired");
        }
    }
    
    private PaymentResponse createErrorResponse(String message) {
        PaymentResponse response = new PaymentResponse();
        response.setStatus("ERROR");
        response.setMessage(message);
        return response;
    }
    
    private String generateTransactionId() {
        return "TXN" + System.currentTimeMillis() + Math.abs((int) (Math.random() * 10000));
    }
}

